(LOCALES.de,{"seedBill.healthInsurance":"Krankenversicherung","seedBill.rent":"Miete","seedBill.personalLoan":"Privatkredit","seedBill.medicalBill":"Arztrechnung","seedBill.phone":"Telefon","seedBill.water":"Wasser","seedBill.storageUnit":"Lagerraum","seedBill.rentersInsurance":"Hausratversicherung","seedBill.trashService":"Müllabfuhr","seedBill.petInsurance":"Tierversicherung","seedBill.studentLoan":"Studienkredit","seedBill.creditCard":"Kreditkarte"}),RETURNED_I18N.de=["Gegen alle Wahrscheinlichkeit hat {name} es geschafft. Das Fieber brach im Morgengrauen.","{name} hätte tot sein müssen. Stattdessen öffneten sich die Augen.","Nach allem Ermessen hätte {name} nicht überleben dürfen. Doch es geschah.","{name} kam vom Rand zurück. Das Lager ist seither stiller.","{name} lebt. Niemand hat damit gerechnet."],WEDDINGS_I18N.de=["{aName} und {bName} haben heute geheiratet. Sie nehmen den Namen {sharedLast} an.","{aName} und {bName} traten heute Morgen vor {leaderName} und sprachen die Worte. Jetzt sind sie die {sharedLast}s.","{leaderName} traute {aName} und {bName} im Hof. Die {sharedLast}s gingen Hand in Hand hinaus. Das Lager klatschte länger als beabsichtigt.","{aName} und {bName} nahmen heute den Namen {sharedLast} an. {leaderName} las aus einem gefundenen Taschenbuch. Niemand hatte etwas dagegen.","Es war kurz. {leaderName} sprach die Worte; {aName} und {bName} sprachen ihre eigenen. Die {sharedLast}s gingen zum Essen wie an jedem anderen Abend."],Object.assign(LOCALES.de,{"ach.earnedOf":"{earned} von {total} erreicht."}),Object.assign(LOCALES.de,{"orders.board":"Lagerbefehle","orders.fireLit":"Signalfeuer · brennt","orders.fireOut":"Signalfeuer · erloschen","orders.streakLabel":"Befehlsserie {n}","orders.rewardLabel":"Belohnung +{n} XP","orders.rewardEarned":"+{n} XP erhalten","orders.cleanMonth.name":"Ein sauberer Monat","orders.cleanMonth.desc":"Jede in diesem Monat fällige Rechnung pünktlich begleichen.","orders.ahead.name":"Den Toten voraus","orders.ahead.desc":"Vor dem Fälligkeitsdatum zahlen — zwei Tage oder mehr.","orders.hold.name":"Die Linie halten","orders.hold.desc":"Die verlustfreie Serie auf {n} bringen.","orders.quiet.name":"Ein stiller Monat","orders.quiet.desc":"Nichts überfällig werden lassen.","orders.stockpile.name":"Der Vorrat","orders.doneLine":"Befehle ausgeführt. Die Tafel ist gewischt.","orders.failLine":"Die Befehle bleiben unerfüllt. Niemand sagt etwas.","orders.logNew":"Neue Befehle an der Tafel: {name}.","orders.logDone":"Befehle ausgeführt — {name}. Das Lager gönnt sich ein Nicken.","orders.logFail":"Der Monat endet, {name} bleibt unerfüllt. Die Tafel ist gewischt.","orders.logStockNew":"{n} Fälligkeiten ballen sich wie eine Horde. Der Vorrat ist angeschlagen.","orders.logStockDone":"Der Vorrat hält. Jede Fälligkeit eingehalten.","orders.logStockFail":"Der Vorrat bricht — eine ist durchgerutscht.","ribbon.orders":"Befehle: {n}","ribbon.sOrders":"Befehle {n}","guide.ordersTitle":"Lagerbefehle","guide.ordersP1":"Befehle erscheinen an der Tafel zu ihren eigenen Stunden — zufällig gezogen aus den Aufgaben, die die Lage des Lagers zulässt, nie nach einem Plan, den irgendwer einsehen könnte. Wer einen erfüllt, erhält Bonus-XP; früher oder später taucht der nächste auf. Aufeinanderfolgende Erfolge bilden eine Serie, die den Bonus vervielfacht und das Signalfeuer am Brennen hält.","guide.ordersP2":"Ein verpatzter Monat setzt die Serie zurück und löscht das Feuer. Mehr nicht. Kein Überlebender kommt durch die Tafel je zu Schaden — sie antworten nur den Rechnungen selbst."}),Object.assign(LOCALES.de,{"orders.weekQuiet.name":"Eine stille Woche","orders.weekQuiet.desc":"Sieben Tage ab diesem Anschlag wird nichts überfällig.","orders.firstStrike.name":"Erstschlag","orders.firstStrike.desc":"Binnen drei Tagen nach diesem Anschlag eine Rechnung pünktlich begleichen.","orders.doubleTap.name":"Doppelschlag","orders.doubleTap.desc":"Zwei pünktliche Zahlungen — am selben Tag.","orders.backToBack.name":"Schlag auf Schlag","orders.backToBack.desc":"Pünktliche Zahlungen an zwei Tagen hintereinander.","orders.brink.name":"Auf der Kante","orders.brink.desc":"Eine Rechnung exakt am Fälligkeitstag begleichen. Keinen Tag früher, keinen später.","orders.steadyHand.name":"Ruhige Hände","orders.steadyHand.desc":"Drei pünktliche Zahlungen, nichts Überfälliges dazwischen.","orders.veteran.name":"Den Veteranen versorgen","orders.veteran.desc":"Das älteste Lagermitglied: {name}. Pünktlich begleichen.","orders.bigGame.name":"Großwild","orders.bigGame.desc":"Die schwerste Rechnung im Buch: {name}. Pünktlich erlegen.","orders.scout.name":"Der am Tor","orders.scout.desc":"Die nächste Fälligkeit: {name}. Einhalten.","orders.rescue.name":"Niemand bleibt zurück","orders.rescue.desc":"Überfällig: {name}. Nach Hause holen — begleichen.","orders.convoy.name":"Der Konvoi","orders.convoy.desc":"Drei Rechnungen im Voraus begleichen — zwei Tage oder mehr.","orders.vanguard.name":"Vorhut","orders.vanguard.desc":"Eine Rechnung eine ganze Woche im Voraus begleichen."}),Object.assign(LOCALES.de,{"orders.idleTitle":"Die Tafel ist leer","orders.idleDesc":"Befehle kommen, wann sie kommen."}),Object.assign(LOCALES.de,{"guide.badgesTitle":"Dienstabzeichen","guide.badgesIntro":"Dauerhafte Auszeichnungen auf der Anführerkarte. Sie markieren die Bestmarken des ganzen Lagers und überstehen jeden Neustart — einmal verdient, geht ein Abzeichen nie verloren. Jedes steigt in Stufen, während der Rekord wächst. Tippe auf ein Abzeichen, um die volle Bestenliste zu öffnen.","guide.badge_bestCleanRun":"Deine längste Folge pünktlicher Zahlungen ohne eine einzige verspätete. Stufen bei {tiers}.","guide.badge_bestStreak":"Deine beste Serie pünktlicher Zahlungen. Stufen bei {tiers}.","guide.badge_biggestCamp":"Die meisten Überlebenden, die das Lager je zugleich hielt. Stufen bei {tiers}.","guide.badge_longestLivedDays":"Die meisten Tage, die ein einzelner Überlebender an deiner Seite stand. Verdient bei {tiers} Tagen.","guide.badge_ordersCompleted":"Insgesamt erfüllte Lagerbefehle. Stufen bei {tiers}."}),ANNIVERSARIES_I18N.de={first:["{name} hält nun schon ein ganzes Jahr mit dem Lager. Keine Reden — jemand legte nur eine zusätzliche Ration an die Pritsche.","Vor einem Jahr, heute, kam {name} als Fremder durchs Tor. Das Lager erinnert sich an keine Zeit mehr davor.","{name} verzeichnete heute ein Jahr im Lager, verbracht auf Wache wie jede andere Nacht. Es passte zu ihm.","Ein Jahr für {name}. Der Anführer kritzelte ein kleines Zeichen neben den Namen an die Wand. Das war alles. Es genügte."],many:["{years} Jahre nun, seit {name} ankam. Die Neuen glauben, er sei immer schon hier gewesen.","{name} hält seit {years} Jahren mit dem Lager — lang genug, dass seine Geschichten eigene Geschichten haben.","{years} Jahre für {name}. Die Wand an der Pritsche ist voller Zeichen; er hat aufgehört zu zählen. Das Lager nicht.","{name} erreichte heute {years} Jahre im Lager. Der Anführer sagte nichts, nickte nur übers Feuer. {name} nickte zurück."]},Object.assign(LOCALES.de,{"mg.exitTitle":"Einsatz verlassen?","mg.exitMsg":"Wer jetzt geht, verbraucht einen Versuch und verliert die bisher zurückgeholten XP. Die Horde bleibt — du kannst nicht erneut spielen.","mg.exitStay":"Weiterspielen","mg.exitLeave":"Trotzdem verlassen","mg.play":"Spielen","mg.dismissOne":"Eine verwerfen","mg.dismissAll":"Alle verwerfen","mg.close":"Schließen","mg.pickerSubOne":"Eine Horde ist los. Einen Trupp ausrücken?","mg.pickerSubMany":"{n} Horden sind los. Einen Trupp ausrücken?","mg.toggleLabel":"Einsätze aus Rechnungen","mg.toggleOn":"Einsätze werden aus Rechnungen verdient","mg.toggleOff":"Keine Einsätze mehr aus Rechnungen","mg.backToCamp":"Zurück zum Lager","aria.prevMonth":"Voriger Monat","aria.nextMonth":"Nächster Monat","aria.addBill":"Rechnung hinzufügen"}),Object.assign(ACHIEVEMENTS_I18N.de,{horde_first:{name:"Erstes Blut",desc:"Führe deinen ersten Trupp hinaus, um die Horde zu vernichten."},horde_slayer:{name:"Boss-Töter",desc:"Strecke einen Horden-Boss nieder."},horde_exterminator:{name:"Kammerjäger",desc:"Räume die Horde fünfmal auf."},horde_full:{name:"Volle Truppe",desc:"Stelle vierzig Überlebende gleichzeitig in einem Einsatz auf."},horde_untouched:{name:"Unversehrt",desc:"Schließe einen Einsatz ab, ohne einen einzigen Überlebenden zu verlieren."}}),Object.assign(LOCALES.de,{"story.hordeCleared":"{leader} führte einen Trupp in die Straßen und zerschlug die Horde. Der Verwandelte wurde erlegt — das Lager atmet wieder.","story.hordeWiped":"{leader} zog mit einem Trupp los, um die Horde zu zerschlagen, und wurde in den Straßen überrannt."});